  const root = document.documentElement;
  const appShell = document.querySelector('.h-dvh') || document.body;
  const terminal = document.querySelector('.ao-terminal, .xterm');
  const rootStyle = getComputedStyle(root);
  const shellStyle = getComputedStyle(appShell);
  const terminalStyle = terminal ? getComputedStyle(terminal) : null;
  return {
    url: location.href,
    title: document.title,
    shellClass: appShell?.getAttribute('class'),
    shellFontFamily: shellStyle.fontFamily,
    rootFontSans: rootStyle.getPropertyValue('--font-sans').trim(),
    rootFontMono: rootStyle.getPropertyValue('--font-mono').trim(),
    rootFontTerminal: rootStyle.getPropertyValue('--font-terminal').trim(),
